INSERT INTO TMDB.MOVIE (MOVIE_ID,POSTER_URL,TITLE,MOVIE_RATING,OPEN_DATE,OPEN_COUNTRY,RUNNING_TIME,INTRODUCE,SYNOPSIS,ORIGINAL_TITLE,STATE,"LANGUAGE",BUDGET,PROFIT) VALUES
	 ('MV-20260227-000003','데몬 헌터스2 포스터 URL','Untitled KPop Demon Hunters Sequel',NULL,NULL,NULL,NULL,NULL,'The second installment in the franchise. Plot TBA.',NULL,'제작예정','영어',NULL,NULL),
	 ('MV-20260227-000001','데몬헌터스 포스터 URL','케이팝 데몬 헌터스','12',TIMESTAMP'2025-10-31 00:00:00','KR',96,'They sing. They dance. They battle demons.','케이팝 슈퍼스타 루미, 미라, 조이. 매진을 기록하는 대형 스타디움 공연이 없을 때면 이들은 또 다른 활동에 나선다. 바로 비밀 능력을 이용해 팬들을 초자연적 위협으로부터 보호하는 것.','KPop Demon Hunters','개봉됨','영어',100000000,24690793),
	 ('MV-20260227-000002','헬프! 포스터 URL','헬프!','u',TIMESTAMP'1965-07-29 00:00:00','GB',92,'Stop worrying! HELP! is on the way!','우연히 암흑의 여왕에 바쳐지는 제물이 된 링고를 구하기 위해 비틀즈 멤버들이 고군분투한다.','Help!','개봉됨','영어',100000000,NULL),
	 ('MV-20260227-000004','인터스텔라 포스터 URL','인터스텔라','12',TIMESTAMP'2014-11-06 00:00:00','KR',169,'우린 답을 찾을 것이다, 늘 그랬듯이','세계 각국의 정부와 경제가 완전히 붕괴된 미래가 다가온다. 지난 20세기에 범한 잘못이 전 세계적인 식량 부족을 불러왔고, NASA도 해체되었다. 나사 소속 우주비행사였던 쿠퍼는 지구에 몰아친 식량난으로 옥수수나 키우며 살고 있다. 거센 황사가 몰아친 어느 날 알 수 없는 힘에 이끌려 딸과 함께 도착한 곳은 인류가 이주할 행성을 찾는 나사의 비밀본부. 이 때 시공간에 불가사의한 틈이 열리고, 이 곳을 탐험해 인류를 구해야 하는 임무를 위해 쿠퍼는 만류하는 딸을 뒤로한 채 우주선에 탑승하는데...','Interstellar','개봉됨','영어',165000000,746606706),
	 ('MV-20260227-000005','쉘터 포스터 URL','쉘터','15',TIMESTAMP'2026-01-30 00:00:00','GB',108,'Her safety. His mission.','과거를 등진 채 침묵의 섬에 숨어든 남자, 아이를 구한 순간 잠들었던 본능이 깨어난다. 스코틀랜드의 외딴 섬 lighthouse에서 개 한 마리와 함께 은둔하며 살아가는 전직 특수 요원 메이슨. 그는 술과 체스, 그리고 그림으로 과거의 잔혹한 기억을 지우며 스스로를 고립시킨다. 유일한 바깥세상과의 연결고리는 정기적으로 보급품을 나르는 어린 소녀 제시뿐이다. 어느 날, 거센 폭풍우 속에서 목숨을 잃을 위기에 처한 제시를 구하기 위해 그는 평생 지켜온 금기를 깨고 세상 밖으로 모습을 드러낸다. 단 한 번의 자비로운 선택은 도미노처럼 거대한 위협을 불러오고, 메이슨은 자신을 뒤쫓는 과거의 그림자로부터 아이를 지키기 위해 런던의 어두운 지하 세계로 뛰어든다. 가장 소중한 것을 지키기 위해 가장 잔인해져야만 하는 남자의 처절한 생존 여정이 시작된다.','Shelter','개봉됨','영어',50000000,26786795),
	 ('MV-20260227-000006','인셉션 포스터 URL','인셉션','12',TIMESTAMP'2010-07-21 00:00:00','US',148,'Your mind is the scene of the crime.','타인의 꿈에 들어가 생각을 훔치는 특수 보안요원 코브. 그를 이용해 라이벌 기업의 정보를 빼내려는 사이토는 코브에게 생각을 심는 인셉션 작전을 제안한다.','Inception','개봉됨','영어',160000000,839030630),
	 ('MV-20260227-000007','매트릭스 포스터 URL','매트릭스','12',TIMESTAMP'1999-05-15 00:00:00','US',136,'Welcome to the Real World.','서기 2199년, 인공지능 AI에 의해 인류가 재배되고 있는 미래. 낮에는 평범한 회사원, 밤에는 해커로 활동하는 네오는 인류를 구원할 영웅으로 지목되어 매트릭스를 빠져나온다.','The Matrix','개봉됨','영어',63000000,463517383),
	 ('MV-20260227-000008','기생충 포스터 URL','기생충','15',TIMESTAMP'2019-05-30 00:00:00','KR',132,'행복은 나눌수록 커지잖아요.','전원 백수로 살 길 막막하지만 사이는 좋은 기택 가족. 장남 기우에게 명문대생 친구가 연결해 준 고액 과외 자리는 모처럼 싹튼 고정수입의 희망이다.','기생충','개봉됨','한국어',11363000,257591776),
	 ('MV-20260227-000009','듄2 포스터 URL','듄: 파트 2','12',TIMESTAMP'2024-02-28 00:00:00','US',166,'Long live the fighters.','황제의 모략으로 멸문지화를 당한 아트레이데스 가문의 유일한 후계자 폴. 어머니 레이디 제시카와 함께 척박한 모래 행성 아라키스로 도망친 그는 그곳에 숨어 사는 반군 프레멘들과 운명적인 만남을 갖는다.','Dune: Part Two','개봉됨','영어',190000000,714844358),
	 ('MV-20260227-000010','아바타 포스터 URL','아바타','12',TIMESTAMP'2009-12-17 00:00:00','US',162,'Enter the World of Pandora.','지구 에너지 고갈 문제를 해결하기 위해 판도라 행성으로 향한 인류. 하반신 마비의 해병대원 제이크 설리는 아바타 프로그램을 통해 판도라의 토착민 나비족(Navi)의 무리에 합류하게 된다.','Avatar','개봉됨','영어',237000000,2923706026);
